import React from "react";

const stages = [
  { key: "import", label: "Import", color: "blue" },
  { key: "transcription", label: "Transcription", color: "yellow" },
  { key: "relecture", label: "Relecture", color: "purple" },
  { key: "tagging", label: "Tagging", color: "indigo" },
  { key: "validation", label: "Validation", color: "green" },
];

const workflowData = {
  import: [
    {
      id: 2,
      title: "Cassette audio - Interview Leader 2022",
      source: "Cassette",
      date: "10/10/2023",
    },
    {
      id: 6,
      title: "Archives personnelles - Notes manuscrites",
      source: "Notes",
      date: "09/10/2023",
    },
  ],
  transcription: [
    {
      id: 1,
      title: "Transcription cahier sœur Ester KOUONANG - Volume 1",
      assigned: "Marie D.",
      date: "15/10/2023",
    },
  ],
  relecture: [
    {
      id: 3,
      title: "Cahier sœur Henriette MBARGA - Section 3",
      assigned: "Thomas M.",
      date: "12/10/2023",
    },
  ],
  tagging: [
    {
      id: 5,
      title: "Témoignage mission Yaoundé 2021",
      assigned: "Paul M.",
      date: "05/10/2023",
    },
  ],
  validation: [
    {
      id: 4,
      title: "De ses lèvres - Chapitre 7",
      assigned: "Sophie L.",
      date: "08/10/2023",
    },
  ],
};

const Workflow: React.FC = () => (
  <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
    <h2 className="text-xl font-medium text-gray-800 dark:text-white mb-4 flex justify-between items-center">
      <span>Gestion du Workflow</span>
      <div>
        <button
          id="help-drag-drop"
          className="text-sm px-3 py-1 text-primary border border-primary rounded-md hover:bg-primary hover:text-white transition-colors"
        >
          <i className="fas fa-question-circle mr-1"></i> Aide Drag & Drop
        </button>
      </div>
    </h2>

    {/* Instructions drag & drop (affichage statique ici) */}
    <div className="mb-6 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg">
      <h3 className="text-sm font-medium text-blue-800 dark:text-blue-300 mb-2">
        <i className="fas fa-info-circle mr-1"></i> Comment utiliser le glisser-déposer
      </h3>
      <ul className="text-sm text-blue-700 dark:text-blue-400 list-disc pl-5 space-y-1">
        <li>Cliquez et maintenez pour faire glisser un document</li>
        <li>Déplacez-le vers une autre étape du workflow</li>
        <li>Relâchez pour déposer le document dans la nouvelle étape</li>
        <li>Les compteurs de documents se mettront à jour automatiquement</li>
      </ul>
    </div>

    <div className="workflow-container flex flex-nowrap overflow-x-auto pb-4 gap-4">
      {stages.map((stage, idx) => (
        <div
          key={stage.key}
          className={`workflow-stage min-w-[280px] bg-gray-50 dark:bg-gray-700 rounded-lg shadow p-4`}
          data-stage={stage.key}
        >
          <div className="flex justify-between items-center mb-4">
            <h3 className="font-medium text-gray-800 dark:text-white flex items-center">
              <span
                className={`w-6 h-6 bg-${stage.color}-100 dark:bg-${stage.color}-900 text-${stage.color}-600 dark:text-${stage.color}-400 rounded-full flex items-center justify-center text-xs mr-2`}
              >
                {idx + 1}
              </span>
              {stage.label}
            </h3>
            <span
              className={`document-counter text-xs font-medium rounded-full bg-${stage.color}-100 dark:bg-${stage.color}-900 text-${stage.color}-600 dark:text-${stage.color}-400 px-2 py-1`}
            >
              {workflowData[stage.key as keyof typeof workflowData]?.length || 0}{" "}
              {workflowData[stage.key as keyof typeof workflowData]?.length > 1
                ? "documents"
                : "document"}
            </span>
          </div>

          <div className="drop-indicator">
            <i className="fas fa-arrow-down text-lg mb-1"></i>
            <p>Déposer le document ici</p>
          </div>

          <div className="document-list space-y-3">
            {workflowData[stage.key as keyof typeof workflowData]?.map((doc: any) => (
              <div
                key={doc.id}
                className={`workflow-item bg-white dark:bg-gray-800 rounded p-3 border-l-4 border-${stage.color}-400 dark:border-${stage.color}-600 shadow-sm cursor-grab`}
                draggable={true}
                data-doc-id={`doc-${doc.id}`}
                data-current-stage={stage.key}
              >
                <div className="flex justify-between items-start">
                  <h4 className="text-sm font-medium text-gray-800 dark:text-white">
                    {doc.title}
                  </h4>
                  <i className="fas fa-grip-vertical text-gray-400 ml-2"></i>
                </div>
                <div className="flex justify-between items-center mt-2 text-xs text-gray-500 dark:text-gray-400">
                  {doc.assigned ? (
                    <>
                      <span>Assigné: {doc.assigned}</span>
                      <span>{doc.date}</span>
                    </>
                  ) : (
                    <>
                      <span>Source: {doc.source}</span>
                      <span>{doc.date}</span>
                    </>
                  )}
                </div>
              </div>
            ))}
          </div>

          <button className="w-full mt-4 py-2 text-sm bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors">
            <i className="fas fa-plus mr-1"></i> Ajouter document
          </button>
        </div>
      ))}
    </div>

    <div className="mt-6 bg-blue-50 dark:bg-blue-900/20 p-4 rounded-lg">
      <h3 className="text-sm font-medium text-blue-800 dark:text-blue-300 mb-2">
        Configuration du Workflow
      </h3>
      <p className="text-sm text-blue-700 dark:text-blue-400">
        Vous pouvez personnaliser les étapes du workflow, définir des règles de validation et configurer les notifications pour chaque transition.{" "}
        <a href="#" className="text-primary font-medium">
          Accéder aux paramètres <i className="fas fa-arrow-right ml-1"></i>
        </a>
      </p>
    </div>
  </div>
);

export default Workflow;
